Passe o mouse sobre as barras para ver os detalhes.

dados = d3.csv("https://docs.google.com/spreadsheets/d/e/2PACX-1vR_kABBziuLQDcgkwtThORXGuhxlp9G1mWXsb9Xv6XzB9T4K47YFWr6oRXahriBjqsIeQgl1pe_stIe/pub?gid=0&single=true&output=csv")
demandas_proto = dados.filter(d =&gt; d.Categoria === "Conceito Urbano")

// Gráfico interativo com design ajustado para tema escuro
Plot.plot({
  style: { background: "transparent", color: "#e0e0e0", fontSize: "14px", fontFamily: "inherit" },
  marginLeft: 50,
  marginBottom: 60,
  x: { label: null, tickRotate: -25 },
  y: { label: "Demandas", grid: true },
  color: { 
    legend: true, 
    // Paleta de cores baseada nos status
    domain: ["Pendente", "Em andamento", "Concluído"],
    range: ["#dc3545", "#0dcaf0", "#198754"] 
  },
  marks: [
    Plot.barY(demandas_proto, Plot.groupX(
      { y: "count" }, 
      { 
        x: "Setor", 
        fill: "Status", 
        tip: true, // Adiciona tooltip ao passar o mouse
        rx: 4,     // Arredonda as pontas das barras
        inset: 1   // Espaçamento sutil entre as barras
      }
    ))
  ]
})

